extension StringKengaytma on String {
  String boshHarfKatta() =>
      isEmpty ? this : '${this[0].toUpperCase()}${substring(1)}';
  bool get emailMi => contains('@') && contains('.');
}

void main() {
  Inson('Alisher').yur();
  print('salom'.boshHarfKatta()); // Salom
  print('test@gmail.com'.emailMi); // true
}
```

