class BankHisobi {
  String ism;
  double _balans;

  BankHisobi({required this.ism, double balans = 0.0}) : _balans = balans;

  void pul_qo'yish(double miqdor) {
    _balans += miqdor;
    print('Hisobga ${miqdor.toStringAsFixed(0)} so\'m qo\'yildi. Jami: $_balans');
  }

  void pul_olish(double miqdor) {
    if (miqdor > _balans) { print('Yetarli mablag\' yo\'q!'); return; }
    _balans -= miqdor;
    print('Hisobdan ${miqdor.toStringAsFixed(0)} so\'m olindi. Qoldi: $_balans');
  }

  double get holat => _balans;

  Future<String> serverGaJo'natish() async {
    await Future.delayed(Duration(seconds: 1));
    return 'Server javobi: Tranzaksiya tasdiqlandi';
  }

  @override
  String toString() => '$ism — Balans: $_balans so\'m';
}

void main() async {
  var hisob = BankHisobi(ism: 'Ali', balans: 0);
  hisob.pul_qo'yish(500000);
  hisob.pul_olish(200000);
  hisob.pul_olish(500000);
  print(hisob);
  print(await hisob.serverGaJo'natish());
}

