StatefulWidget — o'zgaruvchan davlatga (state) ega widget. Foydalanuvchi bilan interaktivlik kerak bo'lganda ishlatiladi.

## StatefulWidget Tuzilmasi
```dart
class Hisoblagich extends StatefulWidget {
  final String sarlavha;
  const Hisoblagich({super.key, required this.sarlavha});
  @override
  State<Hisoblagich> createState() => _HisoblagichState();
}

class _HisoblagichState extends State<Hisoblagich> {
  int _son = 0;
  bool _faol = true;

  @override
  Widget build(BuildContext context) {
    return Column(
      children: [
        Text(widget.sarlavha),
        Text('$_son'),
        ElevatedButton(
          onPressed: _faol ? _oshirish : null,
          child: const Text('+'),
        ),
      ],
    );
  }

  void _oshirish() {
    setState(() {
      _son++;
      if (_son >= 10) _faol = false;
    });
  }
}
```

## Lifecycle
```dart
class _LifecycleMisolState extends State<LifecycleMisol> {
  // 1. initState — bir marta, widget yaratilganda
  @override
  void initState() {
    super.initState();
    _malumotYukla();
  }

  // 2. didChangeDependencies — context tayyor bo'lganda
  @override
  void didChangeDependencies() {
    super.didChangeDependencies();
  }

  // 3. build — har setState'da qayta chaqiriladi
  @override
  Widget build(BuildContext context) => Text('...');

  // 4. didUpdateWidget — ota-widget yangilanganda
  @override
  void didUpdateWidget(covariant LifecycleMisol old) {
    super.didUpdateWidget(old);
  }

  // 5. dispose — widget yo'q qilinganda
  @override
  void dispose() {
    // Timer, Controller, Stream tozalash
    super.dispose();
  }

  Future<void> _malumotYukla() async {
    await Future.delayed(const Duration(seconds: 2));
    if (mounted) setState(() {});
  }
}
```

