class _SekundomerState extends State<Sekundomer> {
  Timer? _timer;
  int _ms = 0;
  bool _ishlayapti = false;

  @override void dispose() { _timer?.cancel(); super.dispose(); }

  void _boshlash() {
    setState(() => _ishlayapti = true);
    _timer = Timer.periodic(const Duration(milliseconds: 100), (_) {
      if (mounted) setState(() => _ms += 100);
    });
  }
  void _toxtatish() { _timer?.cancel(); setState(() => _ishlayapti = false); }
  void _reset() { _timer?.cancel(); setState(() { _ms = 0; _ishlayapti = false; }); }

  String get _format {
    int d = _ms ~/ 60000, s = (_ms ~/ 1000) % 60, ds = (_ms ~/ 100) % 10;
    return '${d.toString().padLeft(2,'0')}:${s.toString().padLeft(2,'0')}.$ds';
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('Sekundomer'), centerTitle: true),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Text(_format, style: const TextStyle(fontSize: 64, fontWeight: FontWeight.bold, fontFamily: 'monospace')),
            const SizedBox(height: 48),
            Row(mainAxisAlignment: MainAxisAlignment.center, children: [
              ElevatedButton(
                onPressed: _ishlayapti ? _toxtatish : _boshlash,
                style: ElevatedButton.styleFrom(backgroundColor: _ishlayapti ? Colors.red : Colors.green, foregroundColor: Colors.white, padding: const EdgeInsets.symmetric(horizontal: 40, vertical: 16)),
                child: Text(_ishlayapti ? 'To\'xtat' : 'Boshlash', style: const TextStyle(fontSize: 18)),
              ),
              const SizedBox(width: 16),
              OutlinedButton(onPressed: _reset, style: OutlinedButton.styleFrom(padding: const EdgeInsets.symmetric(horizontal: 32, vertical: 16)), child: const Text('Reset', style: TextStyle(fontSize: 18))),
            ]),
          ],
        ),
      ),
    );
  }
}

