    return Scaffold(
      body: RefreshIndicator(
        onRefresh: _yangilash,
        child: CustomScrollView(
          slivers: [
            SliverAppBar(
              expandedHeight: 180,
              pinned: true,
              flexibleSpace: FlexibleSpaceBar(
                title: Text('Katalog'),
