```dart
try {
  final response = await dio.get('/users');
} on DioException catch (e) {
  switch (e.type) {
    case DioExceptionType.connectionTimeout:
      print('Ulanish vaqti tugadi');
    case DioExceptionType.receiveTimeout:
      print('Javob vaqti tugadi');
