Future<List<Map<String, dynamic>>> getUsersWithPosts() async {
  final database = await db.database;
  return await database.rawQuery('''
    SELECT u.name, COUNT(p.id) as post_count
    FROM users u
    LEFT JOIN posts p ON u.id = p.user_id
    GROUP BY u.id
    ORDER BY post_count DESC
  ''');
}

// Transaction — atomik operatsiyalar
Future<void> transferData() async {
  final database = await db.database;
  await database.transaction((txn) async {
    await txn.delete('old_table', where: 'id = ?', whereArgs: [1]);
    await txn.insert('new_table', {'data': 'transferred'});
    // Xato bo'lsa ikkalasi ham rollback bo'ladi
  });
}
