**Email/Parol bilan Ro'yxatdan o'tish:**
```dart
class AuthService {
  final FirebaseAuth _auth = FirebaseAuth.instance;

  // Ro'yxatdan o'tish
  Future<UserCredential?> signUp(String email, String password) async {
    try {
      return await _auth.createUserWithEmailAndPassword(
        email: email,
        password: password,
      );
    } on FirebaseAuthException catch (e) {
      switch (e.code) {
        case 'weak-password': throw Exception('Parol juda zaif');
        case 'email-already-in-use': throw Exception('Bu email allaqachon ishlatilgan');
        case 'invalid-email': throw Exception('Noto\'g\'ri email formati');
        default: throw Exception('Xato: ${e.message}');
      }
    }
  }

  // Kirish
  Future<UserCredential?> signIn(String email, String password) async {
    try {
      return await _auth.signInWithEmailAndPassword(
        email: email,
        password: password,
      );
    } on FirebaseAuthException catch (e) {
      switch (e.code) {
        case 'user-not-found': throw Exception('Foydalanuvchi topilmadi');
        case 'wrong-password': throw Exception('Noto\'g\'ri parol');
        default: throw Exception(e.message);
      }
    }
  }

  // Chiqish
  Future<void> signOut() async => _auth.signOut();

  // Joriy foydalanuvchi
  User? get currentUser => _auth.currentUser;

  // Auth holati oqimi
  Stream<User?> get authStateChanges => _auth.authStateChanges();

  // Parolni tiklash
  Future<void> resetPassword(String email) async {
    await _auth.sendPasswordResetEmail(email: email);
  }

  // Profilni yangilash
  Future<void> updateProfile(String displayName) async {
    await _auth.currentUser?.updateDisplayName(displayName);
  }
}
