```

**FCM sozlash:**
```dart
class NotificationService {
  final _messaging = FirebaseMessaging.instance;

  Future<void> init() async {
    // Ruxsat so'rash
    await _messaging.requestPermission(
      alert: true, badge: true, sound: true,
    );

    // FCM Token olish (serverga yuboriladi)
    final token = await _messaging.getToken();
    print('FCM Token: $token');

    // Token'ni Firestore'ga saqlash
    if (token != null) {
      await FirebaseFirestore.instance
        .collection('users')
        .doc(FirebaseAuth.instance.currentUser?.uid)
        .update({'fcmToken': token});
    }

    // Foreground xabarlarni ko'rsatish sozlamasi
    await FirebaseMessaging.instance
      .setForegroundNotificationPresentationOptions(
        alert: true, badge: true, sound: true,
      );

    // Foreground xabarlarni tinglash
    FirebaseMessaging.onMessage.listen((RemoteMessage message) {
      print('Foreground xabar: ${message.notification?.title}');
      _showLocalNotification(message);
    });

    // Background'da bosilganda
    FirebaseMessaging.onMessageOpenedApp.listen((RemoteMessage message) {
      print('Bildirishnoma bosildi: ${message.data}');
      // Tegishli sahifaga yo'naltirish
    });
  }

  void _showLocalNotification(RemoteMessage message) {
    // flutter_local_notifications bilan ko'rsatish
  }

  // Mavzuga obuna bo'lish
  Future<void> subscribeToTopic(String topic) async {
    await _messaging.subscribeToTopic(topic);
  }
}

// main():
void main() async {
  WidgetsFlutterBinding.ensureInitialized();
  await Firebase.initializeApp(options: DefaultFirebaseOptions.currentPlatform);

  // Background message handler (top-level funksiya bo'lishi shart)
  FirebaseMessaging.onBackgroundMessage(_backgroundMessageHandler);

  await NotificationService().init();
  runApp(MyApp());
}

@pragma('vm:entry-point')
Future<void> _backgroundMessageHandler(RemoteMessage message) async {
  await Firebase.initializeApp(options: DefaultFirebaseOptions.currentPlatform);
  print('Background xabar: ${message.messageId}');
}
```

