import 'package:flutter/material.dart';
import 'package:flutter_localizations/flutter_localizations.dart';
import 'package:flutter_gen/gen_l10n/app_localizations.dart';
import 'package:intl/intl.dart';

void main() => runApp(const MyApp());

class MyApp extends StatefulWidget {
  const MyApp({super.key});
  @override
  State<MyApp> createState() => _MyAppState();
}

class _MyAppState extends State<MyApp> {
  Locale _locale = const Locale('uz');
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      locale: _locale,
      supportedLocales: const [Locale('uz'), Locale('ru'), Locale('en')],
      localizationsDelegates: const [
        AppLocalizations.delegate,
        GlobalMaterialLocalizations.delegate,
        GlobalWidgetsLocalizations.delegate,
        GlobalCupertinoLocalizations.delegate,
      ],
      home: HomePage(onLocaleChange: (l) => setState(() => _locale = l)),
    );
  }
}

class HomePage extends StatelessWidget {
  final Function(Locale) onLocaleChange;
  const HomePage({super.key, required this.onLocaleChange});
  @override
  Widget build(BuildContext context) {
    final l10n = AppLocalizations.of(context)!;
    final dateStr = DateFormat.yMMMMd(Localizations.localeOf(context).toString()).format(DateTime.now());
    return Scaffold(
      appBar: AppBar(title: Text(l10n.appTitle)),
      body: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text(l10n.welcomeMessage('Mukhammad'), style: const TextStyle(fontSize: 20, fontWeight: FontWeight.bold)),
            Text(l10n.lessonCount(5)),
            Text(l10n.lessonCount(1)),
            Text(l10n.lessonCount(0)),
            Text(l10n.todayDate(dateStr)),
            const SizedBox(height: 20),
            Text(l10n.chooseLanguage),
            Row(
              children: [
                for (final l in ['uz','ru','en'])
                  Padding(
                    padding: const EdgeInsets.only(right: 8),
                    child: ElevatedButton(
                      onPressed: () => onLocaleChange(Locale(l)),
                      child: Text(l.toUpperCase()),
                    ),
                  ),
              ],
            ),
          ],
        ),
      ),
    );
  }
}

