## Cart Provider
```dart
import 'package:flutter/foundation.dart';

class CartItem {
  final Product product;
  int quantity;
  CartItem({required this.product, this.quantity = 1});
  double get total => product.price * quantity;
}

class CartProvider extends ChangeNotifier {
  final Map<int, CartItem> _items = {};

  List<CartItem> get items => _items.values.toList();
  int get itemCount => _items.values.fold(0, (sum, item) => sum + item.quantity);
  double get totalPrice => _items.values.fold(0.0, (sum, item) => sum + item.total);

  void addItem(Product product) {
    if (_items.containsKey(product.id)) {
      _items[product.id]!.quantity++;
    } else {
      _items[product.id] = CartItem(product: product);
    }
    notifyListeners();
  }

  void removeItem(int productId) {
    _items.remove(productId);
    notifyListeners();
  }

  void decreaseQuantity(int productId) {
    if (!_items.containsKey(productId)) return;
    if (_items[productId]!.quantity <= 1) {
      removeItem(productId);
    } else {
      _items[productId]!.quantity--;
      notifyListeners();
    }
  }

  void clear() {
    _items.clear();
    notifyListeners();
  }

  bool isInCart(int productId) => _items.containsKey(productId);
}
```

## Product Provider
```dart
class ProductProvider extends ChangeNotifier {
  List<Product> _products = [];
  List<Product> _filtered = [];
  String _searchQuery = '';
  String _selectedCategory = 'Barchasi';
  bool _isLoading = false;
  String? _error;

  List<Product> get products => _filtered;
  bool get isLoading => _isLoading;
  String? get error => _error;

  List<String> get categories => [
    'Barchasi', ..._products.map((p) => p.category).toSet().toList()
  ];

  Future<void> fetchProducts() async {
    _isLoading = true;
    notifyListeners();
    try {
      _products = await ApiService.getProducts();
      _applyFilters();
    } catch (e) {
      _error = e.toString();
    } finally {
      _isLoading = false;
      notifyListeners();
    }
  }

  void search(String query) {
    _searchQuery = query.toLowerCase();
    _applyFilters();
  }

  void filterByCategory(String category) {
    _selectedCategory = category;
    _applyFilters();
  }

  void _applyFilters() {
    _filtered = _products.where((p) {
      final matchSearch = p.title.toLowerCase().contains(_searchQuery) ||
          p.description.toLowerCase().contains(_searchQuery);
      final matchCategory = _selectedCategory == 'Barchasi' ||
          p.category == _selectedCategory;
      return matchSearch && matchCategory;
    }).toList();
    notifyListeners();
  }
}
