## News API Service
```dart
import 'dart:convert';
import 'package:http/http.dart' as http;

class NewsApiService {
  static const _apiKey = 'YOUR_API_KEY'; // newsapi.org dan oling
  static const _base = 'https://newsapi.org/v2';

  static Future<List<Article>> getTopHeadlines({
    String country = 'us',
    String? category,
  }) async {
    final params = {
      'country': country,
      'apiKey': _apiKey,
      if (category != null) 'category': category,
    };
    final uri = Uri.parse('$_base/top-headlines').replace(queryParameters: params);
    final res = await http.get(uri);
    if (res.statusCode == 200) {
      final data = json.decode(res.body);
      return (data['articles'] as List)
          .map((j) => Article.fromJson(j))
          .where((a) => a.title.isNotEmpty && a.title != '[Removed]')
          .toList();
    }
    throw Exception('Yangiliklar yuklanmadi: ${res.statusCode}');
  }

  static Future<List<Article>> searchNews(String query) async {
    final uri = Uri.parse('$_base/everything').replace(queryParameters: {
      'q': query,
      'apiKey': _apiKey,
      'sortBy': 'publishedAt',
      'language': 'en',
      'pageSize': '20',
    });
    final res = await http.get(uri);
    if (res.statusCode == 200) {
      final data = json.decode(res.body);
      return (data['articles'] as List).map((j) => Article.fromJson(j)).toList();
    }
    throw Exception('Qidiruv xatoligi');
  }
}
