## Workout Modeli va Repository
```dart
class Workout {
  final int? id;
  final String name;
  final String type;    // 'Yuguirish', 'Og\'irlik', 'Yoga'
  final int duration;   // daqiqalarda
  final int calories;
  final DateTime date;
  final String? notes;

  const Workout({
    this.id, required this.name, required this.type,
    required this.duration, required this.calories,
    required this.date, this.notes,
  });

  Map<String, dynamic> toMap() => {
    if (id != null) 'id': id,
    'name': name,
    'type': type,
    'duration': duration,
    'calories': calories,
    'date': date.toIso8601String(),
    'notes': notes,
  };

  factory Workout.fromMap(Map<String, dynamic> map) => Workout(
    id: map['id'],
    name: map['name'],
    type: map['type'],
    duration: map['duration'],
    calories: map['calories'],
    date: DateTime.parse(map['date']),
    notes: map['notes'],
  );
}

class WorkoutRepository {
  final _db = DatabaseHelper.instance;

  Future<int> insert(Workout workout) async {
    final db = await _db.database;
    return await db.insert('workouts', workout.toMap());
  }

  Future<List<Workout>> getAll() async {
    final db = await _db.database;
    final maps = await db.query('workouts', orderBy: 'date DESC');
    return maps.map(Workout.fromMap).toList();
  }

  Future<List<Workout>> getByDate(DateTime date) async {
    final db = await _db.database;
    final dateStr = date.toIso8601String().substring(0, 10);
    final maps = await db.query(
      'workouts',
      where: 'date LIKE ?',
      whereArgs: ['$dateStr%'],
    );
    return maps.map(Workout.fromMap).toList();
  }

  Future<Map<String, int>> getWeeklyCalories() async {
    final db = await _db.database;
    final result = <String, int>{};
    for (int i = 6; i >= 0; i--) {
      final date = DateTime.now().subtract(Duration(days: i));
      final dateStr = date.toIso8601String().substring(0, 10);
      final maps = await db.rawQuery(
        'SELECT SUM(calories) as total FROM workouts WHERE date LIKE ?',
        ['$dateStr%'],
      );
      result[dateStr] = (maps.first['total'] as int?) ?? 0;
    }
    return result;
  }

  Future<int> delete(int id) async {
    final db = await _db.database;
    return await db.delete('workouts', where: 'id = ?', whereArgs: [id]);
  }

  Future<int> update(Workout workout) async {
    final db = await _db.database;
    return await db.update(
      'workouts',
      workout.toMap(),
      where: 'id = ?',
      whereArgs: [workout.id],
    );
  }
}
