## Post Service (Like, Follow, Feed)
```dart
class PostService {
  final _db = FirebaseFirestore.instance;

  Stream<List<Post>> getFeed(List<String> followingIds) {
    if (followingIds.isEmpty) {
      return _db
          .collection('posts')
          .orderBy('createdAt', descending: true)
          .limit(20)
          .snapshots()
          .map((s) => s.docs.map(Post.fromFirestore).toList());
    }
    return _db
        .collection('posts')
        .where('userId', whereIn: followingIds)
        .orderBy('createdAt', descending: true)
        .limit(20)
        .snapshots()
        .map((s) => s.docs.map(Post.fromFirestore).toList());
  }

  Future<void> toggleLike(String postId, String userId) async {
    final ref = _db.collection('posts').doc(postId);
    await _db.runTransaction((transaction) async {
      final snap = await transaction.get(ref);
      final likes = List<String>.from(snap['likes'] ?? []);
      if (likes.contains(userId)) {
        likes.remove(userId);
      } else {
        likes.add(userId);
      }
      transaction.update(ref, {'likes': likes});
    });
  }

  Future<String> uploadImage(File imageFile) async {
    final storage = FirebaseStorage.instance;
    final ref = storage.ref().child('posts/${DateTime.now().millisecondsSinceEpoch}.jpg');
    await ref.putFile(imageFile);
    return await ref.getDownloadURL();
  }

  Future<void> createPost({
    required String userId,
    required String userName,
    String? userAvatar,
    required File imageFile,
    required String caption,
    List<String> tags = const [],
  }) async {
    final imageUrl = await uploadImage(imageFile);
    final post = Post(
      id: '', userId: userId, userName: userName,
      userAvatar: userAvatar, imageUrl: imageUrl,
      caption: caption, likes: [], commentCount: 0,
      createdAt: DateTime.now(), tags: tags,
    );
    await _db.collection('posts').add(post.toFirestore());
  }
}
