Supabase — Firebase'ning open-source muqobili bo'lib, PostgreSQL ma'lumotlar bazasi, autentifikatsiya, real-time so'rovlar, fayl saqlash va Edge Functions'ni bir joyda taqdim etadi.

## Firebase vs Supabase

```
FEATURE          | FIREBASE        | SUPABASE
-----------------|-----------------|------------------
Database         | NoSQL (Firestore)| PostgreSQL (SQL)
Auth             | ✅               | ✅
Real-time        | ✅               | ✅ (via WebSocket)
File Storage     | ✅               | ✅
Server Functions | Cloud Functions  | Edge Functions
Open Source      | ❌               | ✅
Free tier        | Cheklangan      | Keng imkoniyat
SQL Support      | ❌               | ✅ (full SQL!)
```

## O'rnatish

```yaml
# pubspec.yaml
dependencies:
  supabase_flutter: ^2.0.0
```

## Supabase'ni sozlash

```dart
// main.dart
import 'package:supabase_flutter/supabase_flutter.dart';

void main() async {
  WidgetsFlutterBinding.ensureInitialized();

  await Supabase.initialize(
    url: 'https://YOUR_PROJECT.supabase.co',
    anonKey: 'YOUR_ANON_KEY',
  );

  runApp(const MyApp());
}

// Global Supabase client
final supabase = Supabase.instance.client;
```

## Autentifikatsiya

```dart
// auth_service.dart
class AuthService {
  final _supabase = Supabase.instance.client;

  // Email bilan ro'yxatdan o'tish
  Future<AuthResponse> signUp({
    required String email,
    required String password,
    required String name,
  }) async {
    return await _supabase.auth.signUp(
      email: email,
      password: password,
      data: {'name': name}, // qo'shimcha ma'lumot
    );
  }

  // Login
  Future<AuthResponse> signIn({
    required String email,
    required String password,
  }) async {
    return await _supabase.auth.signInWithPassword(
      email: email,
      password: password,
    );
  }

  // Google bilan kirish
  Future<void> signInWithGoogle() async {
    await _supabase.auth.signInWithOAuth(
      OAuthProvider.google,
      redirectTo: 'io.supabase.myapp://login-callback/',
    );
  }

  // Chiqish
  Future<void> signOut() async {
    await _supabase.auth.signOut();
  }

  // Joriy foydalanuvchi
  User? get currentUser => _supabase.auth.currentUser;

  // Auth holati o'zgarishini kuzatish
  Stream<AuthState> get authStateChanges =>
      _supabase.auth.onAuthStateChange;
}
```

## Database — CRUD operatsiyalar

```dart
// database_service.dart
class TaskDatabaseService {
  final _supabase = Supabase.instance.client;

  // CREATE — vazifa qo'shish
  Future<Map<String, dynamic>> createTask({
    required String title,
    required String description,
    required String userId,
  }) async {
    final response = await _supabase
        .from('tasks')
        .insert({
          'title': title,
          'description': description,
          'user_id': userId,
          'is_completed': false,
          'created_at': DateTime.now().toIso8601String(),
        })
        .select()
        .single();

    return response;
  }

  // READ — barcha vazifalarni olish
  Future<List<Map<String, dynamic>>> getTasks(String userId) async {
    final response = await _supabase
        .from('tasks')
        .select('*, categories(name, color)')
        .eq('user_id', userId)
        .order('created_at', ascending: false);

    return List<Map<String, dynamic>>.from(response);
  }

  // UPDATE — vazifani yangilash
  Future<void> updateTask(String taskId, Map<String, dynamic> data) async {
    await _supabase
        .from('tasks')
        .update(data)
        .eq('id', taskId);
  }

  // DELETE — vazifani o'chirish
  Future<void> deleteTask(String taskId) async {
    await _supabase
        .from('tasks')
        .delete()
        .eq('id', taskId);
  }

  // REAL-TIME — o'zgarishlarni kuzatish
  Stream<List<Map<String, dynamic>>> watchTasks(String userId) {
    return _supabase
        .from('tasks')
        .stream(primaryKey: ['id'])
        .eq('user_id', userId)
        .order('created_at');
  }
}
