```dart
class HooksDemo extends HookWidget {
  const HooksDemo({super.key});

  @override
  Widget build(BuildContext context) {
    // 1. useState — oddiy state
    final count = useState(0);
    final isLoading = useState(false);
    final name = useState('Flutter');

