// hooks/use_auth.dart
// Custom hook — prefix 'use' bilan boshlanishi shart
ValueNotifier<User?> useCurrentUser() {
  final user = useState<User?>(null);

  useEffect(() {
    final subscription = supabase.auth.onAuthStateChange.listen(
      (event) => user.value = event.session?.user,
    );

    return subscription.cancel;
  }, []);

  return user;
}

// hooks/use_counter.dart
class CounterHook {
  final ValueNotifier<int> count;
  final VoidCallback increment;
  final VoidCallback decrement;
  final VoidCallback reset;

  CounterHook({required this.count, required this.increment,
    required this.decrement, required this.reset});
}

CounterHook useCounter(int initialValue) {
  final count = useState(initialValue);

  final increment = useCallback(() => count.value++, []);
  final decrement = useCallback(() => count.value--, []);
  final reset = useCallback(() => count.value = initialValue, [initialValue]);

  return CounterHook(
    count: count,
    increment: increment,
    decrement: decrement,
    reset: reset,
  );
}

// Ishlatish:
class CounterWidget extends HookWidget {
  @override
  Widget build(BuildContext context) {
    final counter = useCounter(0);

    return Row(
      children: [
        IconButton(onPressed: counter.decrement, icon: Icon(Icons.remove)),
        Text('${counter.count.value}'),
        IconButton(onPressed: counter.increment, icon: Icon(Icons.add)),
      ],
    );
  }
}
