class StopwatchScreen extends HookWidget {
  const StopwatchScreen({super.key});

  @override
  Widget build(BuildContext context) {
    final milliseconds = useState(0);
    final isRunning = useState(false);
    final timerRef = useRef<Timer?>(null);

    useEffect(() {
      return () {
        timerRef.value?.cancel(); // cleanup
      };
    }, []);

    void start() {
      isRunning.value = true;
      timerRef.value = Timer.periodic(
        Duration(milliseconds: 10),
        (_) => milliseconds.value += 10,
      );
    }

    void stop() {
      isRunning.value = false;
      timerRef.value?.cancel();
    }

    void reset() {
      stop();
      milliseconds.value = 0;
    }

    String formatTime(int ms) {
      final centiseconds = (ms ~/ 10) % 100;
      final seconds = (ms ~/ 1000) % 60;
      final minutes = ms ~/ 60000;
      return '${minutes.toString().padLeft(2, '0')}:'
             '${seconds.toString().padLeft(2, '0')}:'
             '${centiseconds.toString().padLeft(2, '0')}';
    }

    return Scaffold(
      appBar: AppBar(title: Text('Stopwatch')),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            Text(
              formatTime(milliseconds.value),
              style: TextStyle(fontSize: 48, fontFamily: 'monospace'),
            ),
            SizedBox(height: 32),
            Row(
              mainAxisAlignment: MainAxisAlignment.center,
              children: [
                ElevatedButton(
                  onPressed: isRunning.value ? stop : start,
                  child: Text(isRunning.value ? 'Stop' : 'Start'),
                ),
                SizedBox(width: 16),
                OutlinedButton(
                  onPressed: reset,
                  child: Text('Reset'),
                ),
              ],
            ),
          ],
        ),
      ),
    );
  }
}

